// menu-dish.service.ts
import { Injectable, inject } from '@angular/core';
import { map, Observable } from 'rxjs';
import { BaseService } from '../Base/base.service';
import { MenuDish } from '../../models';
import { SupabaseService } from '../Base/supabase.service';

@Injectable({ providedIn: 'root' })
export class MenuDishService extends BaseService<MenuDish> {
  private supabase = inject(SupabaseService);

  protected override getTableName(): string {
    return 'menu_dishes';
  }

  // ========== METODI SPECIFICI ==========

  getDishesByMenu$(menuId: string): Observable<MenuDish[]> {
    return this.data$.pipe(
      map(dishes => dishes.filter(d => d.menu_id === menuId && d.is_active))
    );
  }

  /**
   * Aggiunge un piatto a un menu.
   * Il restaurant_id viene aggiunto automaticamente da BaseService.
   */
  async addDishToMenu(
    menuId: string,
    dishId: string,
    categoryId?: string | null,
    displayOrder = 0
  ): Promise<MenuDish | null> {
    // Verifica se il piatto è già presente attivo
    const existing = this.data.find(
      md => md.menu_id === menuId && md.dish_id === dishId && md.is_active
    );
    if (existing) {
      throw new Error('Il piatto è già presente in questo menu');
    }

    // Calcola il prossimo order_index
    const dishesInMenu = this.data.filter(md => md.menu_id === menuId);
    const maxOrder = dishesInMenu.length
      ? Math.max(...dishesInMenu.map(d => d.order_index ?? 0))
      : -1;
    const nextOrder = maxOrder + 1;

    const payload: Partial<MenuDish> = {
      menu_id: menuId,
      dish_id: dishId,
      display_order: displayOrder,
      order_index: nextOrder,
      is_active: true,
    };
    if (categoryId && categoryId.trim()) {
      payload.category_id = categoryId;
    }

    return this.create(payload);
  }

  /**
   * Disattiva un piatto dal menu (soft delete logico).
   */
  async removeDishFromMenu(menuDishId: string): Promise<boolean> {
    return this.update(menuDishId, { is_active: false });
  }

  /**
   * Aggiorna l'ordine di visualizzazione di un piatto nel menu.
   */
  async updateDishOrder(menuDishId: string, displayOrder: number): Promise<boolean> {
    return this.update(menuDishId, { display_order: displayOrder });
  }

  /**
   * Carica solo i piatti di un menu specifico (filtro aggiuntivo).
   */
  async loadDishesForMenu(menuId: string): Promise<void> {
    return this.loadData({ menu_id: menuId });
  }

  /**
   * Ottiene i piatti di un menu con i dettagli del dish e della categoria.
   * Attenzione: la query deve rispettare lo scope del ristorante.
   */
  async getDishesWithDetailsByMenu(menuId: string): Promise<any[]> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return [];

    const { data, error } = await this.supabase
      .getSupabaseClient()
      .from('menu_dishes')
      .select(
        `
          *,
          dish:dishes!dish_id (
            id,
            name,
            description,
            base_price,
            image_url,
            status,
            category_id,
            preparation_time,
            deleted_at
          ),
          category:categories!category_id (
            id,
            name
          )
        `
      )
      .eq('menu_id', menuId)
      .eq('is_active', true)
      .eq('dishes.restaurant_id', restaurantId) // 🔥 Filtro di sicurezza
      .order('order_index', { ascending: true });

    if (error) {
      console.error('Errore recupero piatti dettagliati:', error);
      return [];
    }
    return (data || []).filter((item: any) => item.dish && !item.dish.deleted_at);
  }

  /**
   * Disattiva tutti i piatti di un menu (rimozione logica di massa).
   */
  async removeAllDishesFromMenu(menuId: string): Promise<boolean> {
    try {
      const { error } = await this.supabase
        .getSupabaseClient()
        .from(this.getTableName())
        .update({ is_active: false, updated_at: new Date().toISOString() })
        .eq('menu_id', menuId)
        .eq('is_active', true);

      if (error) throw error;
      await this.loadData(); // refresh
      return true;
    } catch (error) {
      this.handleError('removeAllDishesFromMenu', error);
      return false;
    }
  }

  // ========== METODI DI ORDINAMENTO (con order_index) ==========

  async initializeOrderIndexes(menuId: string): Promise<boolean> {
    try {
      const { data: dishes, error } = await this.supabase
        .getSupabaseClient()
        .from(this.getTableName())
        .select('*')
        .eq('menu_id', menuId)
        .eq('is_active', true)
        .order('created_at');

      if (error) throw error;

      const updates = dishes.map((d, idx) =>
        this.supabase
          .getSupabaseClient()
          .from(this.getTableName())
          .update({ order_index: idx })
          .eq('id', d.id)
      );
      await Promise.all(updates);
      await this.loadData();
      return true;
    } catch (error) {
      this.handleError('initializeOrderIndexes', error);
      return false;
    }
  }

  async moveDishInMenu(menuId: string, dishId: string, direction: 'up' | 'down'): Promise<boolean> {
    try {
      const { data: dishes, error } = await this.supabase
        .getSupabaseClient()
        .from(this.getTableName())
        .select('*')
        .eq('menu_id', menuId)
        .eq('is_active', true)
        .order('order_index');

      if (error) throw error;

      const currentIndex = dishes.findIndex(d => d.dish_id === dishId);
      if (currentIndex === -1) return false;

      const newIndex = direction === 'up' ? currentIndex - 1 : currentIndex + 1;
      if (newIndex < 0 || newIndex >= dishes.length) return false;

      const currentItem = dishes[currentIndex];
      const targetItem = dishes[newIndex];

      // Scambia gli order_index
      await this.supabase
        .getSupabaseClient()
        .from(this.getTableName())
        .update({ order_index: targetItem.order_index })
        .eq('id', currentItem.id);

      await this.supabase
        .getSupabaseClient()
        .from(this.getTableName())
        .update({ order_index: currentItem.order_index })
        .eq('id', targetItem.id);

      await this.loadData();
      return true;
    } catch (error) {
      this.handleError('moveDishInMenu', error);
      return false;
    }
  }

  async reorderDishes(menuId: string, dishIds: string[]): Promise<boolean> {
    try {
      const updates = dishIds.map((dishId, idx) =>
        this.supabase
          .getSupabaseClient()
          .from(this.getTableName())
          .update({ order_index: idx })
          .eq('menu_id', menuId)
          .eq('dish_id', dishId)
      );
      await Promise.all(updates);
      await this.loadData();
      return true;
    } catch (error) {
      this.handleError('reorderDishes', error);
      return false;
    }
  }

  getDishesByMenuOrdered$(menuId: string): Observable<MenuDish[]> {
    return this.data$.pipe(
      map(dishes =>
        dishes
          .filter(d => d.menu_id === menuId && d.is_active)
          .sort((a, b) => (a.order_index ?? 0) - (b.order_index ?? 0))
      )
    );
  }
}